import React, { useState, useEffect } from 'react';
import '../styles/Settings.css';

const API = process.env.REACT_APP_API || 'http://localhost:3001';

export default function Settings() {
  const [settings, setSettings] = useState({
    langue: 'fr',
    theme: 'light',
    notificationsEmail: true,
    notificationsPush: true,
    affichageRappels: true
  });
  const [loading, setLoading] = useState(true);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      const res = await fetch(`${API}/api/settings`);
      if (res.ok) {
        const data = await res.json();
        setSettings(data);
      }
      setLoading(false);
    } catch (err) {
      console.error('Erreur:', err);
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setSettings(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
    setSaved(false);
  };

  const handleSave = async () => {
    try {
      const res = await fetch(`${API}/api/settings`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(settings)
      });
      if (res.ok) {
        setSaved(true);
        setTimeout(() => setSaved(false), 3000);
      }
    } catch (err) {
      console.error('Erreur lors de la sauvegarde:', err);
    }
  };

  if (loading) {
    return <div className="settings-container loading">Chargement...</div>;
  }

  return (
    <div className="settings-container">
      <div className="settings-header">
        <h1>⚙️ Paramètres</h1>
        <p>Gérez vos préférences et paramètres d'application</p>
      </div>

      {saved && <div className="settings-message success">✓ Paramètres sauvegardés avec succès</div>}

      <div className="settings-grid">
        {/* Section Langue */}
        <div className="settings-section">
          <div className="section-icon">🌐</div>
          <h2>Langue</h2>
          <select name="langue" value={settings.langue} onChange={handleChange} className="input-select">
            <option value="fr">Français</option>
            <option value="en">English</option>
            <option value="ar">العربية</option>
          </select>
        </div>

        {/* Section Thème */}
        <div className="settings-section">
          <div className="section-icon">🎨</div>
          <h2>Thème</h2>
          <select name="theme" value={settings.theme} onChange={handleChange} className="input-select">
            <option value="light">Clair</option>
            <option value="dark">Sombre</option>
            <option value="auto">Auto</option>
          </select>
        </div>

        {/* Section Notifications */}
        <div className="settings-section">
          <div className="section-icon">🔔</div>
          <h2>Notifications</h2>
          <div className="checkbox-group">
            <label>
              <input
                type="checkbox"
                name="notificationsEmail"
                checked={settings.notificationsEmail}
                onChange={handleChange}
              />
              <span>Notifications par email</span>
            </label>
            <label>
              <input
                type="checkbox"
                name="notificationsPush"
                checked={settings.notificationsPush}
                onChange={handleChange}
              />
              <span>Notifications push</span>
            </label>
          </div>
        </div>

        {/* Section Rappels */}
        <div className="settings-section">
          <div className="section-icon">📅</div>
          <h2>Rappels de vaccination</h2>
          <label>
            <input
              type="checkbox"
              name="affichageRappels"
              checked={settings.affichageRappels}
              onChange={handleChange}
            />
            <span>Afficher les rappels de vaccination</span>
          </label>
        </div>
      </div>

      <button className="btn btn-primary btn-save" onClick={handleSave}>
        💾 Enregistrer les paramètres
      </button>
    </div>
  );
}
